#include <bits/stdc++.h>
using namespace std;

int main(){
    double xa,ya,xb,yb;
    cin>>xa>>ya>>xb>>yb;
    double la,lb;
    if (xa<xb){
        la=xb-xa;
    }else{
        la=xa-xb;
    }
    if (ya<yb){
        lb=yb-ya;
    }else{
        lb=ya-yb;
    }
    cout<<fixed<<setprecision(3)<<sqrt(la*la+lb*lb)<<endl;
    return 0;
}
